import{A as e,f as t,h as n,t as r}from"./chunks/plugin-vue_export-helper.I53torQa.js";var i=JSON.parse(`{"title":"强化学习关键概念","description":"汇总强化学习领域的核心术语与关键概念定义","frontmatter":{"title":"强化学习关键概念","description":"汇总强化学习领域的核心术语与关键概念定义"},"headers":[],"relativePath":"rl/tutorials/keywords.md","filePath":"rl/tutorials/keywords.md","lastUpdated":1782721961000}`),a={name:`rl/tutorials/keywords.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<h1 id="强化学习关键概念" tabindex="-1">强化学习关键概念 <a class="header-anchor" href="#强化学习关键概念" aria-label="Permalink to “强化学习关键概念”">​</a></h1><h2 id="马尔科夫性质" tabindex="-1">马尔科夫性质 <a class="header-anchor" href="#马尔科夫性质" aria-label="Permalink to “马尔科夫性质”">​</a></h2><p>智能体采取的行动 仅以当前状态为条件，而与过去的状态和行动无关 。</p><h2 id="观察-状态" tabindex="-1">观察/状态 <a class="header-anchor" href="#观察-状态" aria-label="Permalink to “观察/状态”">​</a></h2><ul><li>状态 ：对世界状态的完整描述。</li><li>观察 ：对环境/世界状态的部分描述。</li></ul><h2 id="动作" tabindex="-1">动作 <a class="header-anchor" href="#动作" aria-label="Permalink to “动作”">​</a></h2><ul><li>离散动作 ：有限数量的动作，例如向左、向右、向上和向下。</li><li>连续动作 ：动作的无限可能性；例如，在自动驾驶汽车的情况下，驾驶场景有无限可能的动作发生。</li></ul><h2 id="奖励和折扣" tabindex="-1">奖励和折扣 <a class="header-anchor" href="#奖励和折扣" aria-label="Permalink to “奖励和折扣”">​</a></h2><ul><li>奖励 ： RL 中的基本因素。告诉智能体所采取的行动是好是坏。</li><li>RL 算法专注于最大化 累积奖励 。</li><li>奖励假设 ： RL 问题可以表述为（累积）回报的最大化。</li><li>执行折扣 是因为在开始时获得的奖励更有可能发生，因为它们比长期奖励更可预测。</li></ul><h2 id="探索与开发权衡" tabindex="-1">探索与开发权衡 <a class="header-anchor" href="#探索与开发权衡" aria-label="Permalink to “探索与开发权衡”">​</a></h2><ul><li>探索 ：通过尝试随机行动并从环境中接收反馈/回报/奖励来探索环境。</li><li>利用 ：利用我们对环境的了解以获得最大回报。</li><li>Exploration-Exploitation Trade-Off：它平衡了我们想要 探索 环境的程度和我们想要 利用 我们对环境的了解程度。</li></ul><h2 id="策略" tabindex="-1">策略 <a class="header-anchor" href="#策略" aria-label="Permalink to “策略”">​</a></h2><ul><li>策略 ：它被称为智能体的大脑。它告诉我们在给定状态下采取什么行动。</li><li>Optimal Policy：当智能体按照它行事时， 最大化 预期回报*的 Policy。它是通过训练学会的。</li></ul><h2 id="基于策略的方法" tabindex="-1">基于策略的方法： <a class="header-anchor" href="#基于策略的方法" aria-label="Permalink to “基于策略的方法：”">​</a></h2><ul><li>一种解决 RL 问题的方法。</li><li>在这种方法中， Policy 是直接学习的。</li><li>将每个状态映射到该状态下的最佳对应动作。或者在该状态下一组可能的动作的概率分布。</li></ul><h2 id="基于价值的方法" tabindex="-1">基于价值的方法： <a class="header-anchor" href="#基于价值的方法" aria-label="Permalink to “基于价值的方法：”">​</a></h2><ul><li>解决 RL 问题的另一种方法。</li><li>在这里，我们没有训练策略，而是训练了一个 价值函数 ，将每个状态映射到处于该状态的期望值。</li></ul><h2 id="寻找最优策略的方法" tabindex="-1">寻找最优策略的方法 <a class="header-anchor" href="#寻找最优策略的方法" aria-label="Permalink to “寻找最优策略的方法”">​</a></h2><ul><li>基于策略的方法。 该策略通常使用神经网络进行训练，以选择在给定状态下采取的动作。在这种情况下，神经网络输出智能体应该采取的行动，而不是使用价值函数。根据环境接收到的经验，神经网络将重新调整并提供更好的动作。</li><li>基于价值的方法。 在这种情况下，价值函数被训练来输出代表我们政策的状态或状态-动作对的值。但是，此值未定义智能体应采取的操作。相反，我们需要在给定值函数输出的情况下指定智能体的行为。例如，我们可以决定采用一种策略来采取总是能带来最大回报的行动（贪心策略）。总之，该策略是一个贪心策略（或用户做出的任何决定），它使用价值函数的值来决定要采取的行动。</li></ul><h2 id="在基于价值的方法中-我们可以找到两种主要策略" tabindex="-1">在基于价值的方法中，我们可以找到两种主要策略 <a class="header-anchor" href="#在基于价值的方法中-我们可以找到两种主要策略" aria-label="Permalink to “在基于价值的方法中，我们可以找到两种主要策略”">​</a></h2><ul><li>状态值函数。 对于每个状态，如果智能体从该状态开始并遵循策略直到结束，则状态值函数是预期的回报。</li><li>动作价值函数。 与状态值函数相反，动作值函数为每个状态和动作对计算智能体在该状态下开始并采取动作时的预期回报。然后它永远遵循该政策。</li></ul><h2 id="epsilon-贪心策略" tabindex="-1">Epsilon-贪心策略： <a class="header-anchor" href="#epsilon-贪心策略" aria-label="Permalink to “Epsilon-贪心策略：”">​</a></h2><ul><li>强化学习中使用的常见探索策略涉及平衡探索和开发。</li><li>选择具有最高预期奖励的动作，概率为 1-epsilon。</li><li>选择概率为 epsilon 的随机动作。</li><li>Epsilon 通常会随着时间的推移而减少，以将注意力转移到开发上。</li></ul><h2 id="贪心策略" tabindex="-1">贪心策略： <a class="header-anchor" href="#贪心策略" aria-label="Permalink to “贪心策略：”">​</a></h2><ul><li>涉及始终根据当前对环境的了解，选择预期会导致最高奖励的行动。（仅开发）</li><li>总是选择具有最高预期奖励的动作。</li><li>不包括任何探索。</li><li>在具有不确定性或未知最佳操作的环境中可能是不利的。</li></ul><h2 id="表格方法" tabindex="-1">表格方法： <a class="header-anchor" href="#表格方法" aria-label="Permalink to “表格方法：”">​</a></h2><p>状态和动作空间足够小以近似值函数以表示为数组和表格的问题类型。 Q-learning 是表格方法的一个例子，因为表格用于表示不同状态-动作对的值。</p><h2 id="深度-q-学习" tabindex="-1">深度 Q 学习： <a class="header-anchor" href="#深度-q-学习" aria-label="Permalink to “深度 Q 学习：”">​</a></h2><p>训练神经网络在给定状态下逼近该状态下每个可能动作的不同 Q 值的方法。 用于解决观察空间太大而无法应用表格 Q 学习方法的问题。</p><h2 id="时间限制" tabindex="-1">时间限制： <a class="header-anchor" href="#时间限制" aria-label="Permalink to “时间限制：”">​</a></h2><p>当环境状态由帧表示时出现的困难。帧本身不提供时间信息。为了获得时间信息，我们需要将许多帧 堆叠 在一起。</p><h2 id="深度-q-学习的阶段" tabindex="-1">深度 Q 学习的阶段： <a class="header-anchor" href="#深度-q-学习的阶段" aria-label="Permalink to “深度 Q 学习的阶段：”">​</a></h2><ul><li>采样： 执行动作，并将观察到的经验元组存储在 重放存储器中 。</li><li>训练： 随机选择一批元组，神经网络使用梯度下降更新其权重。</li></ul><h2 id="稳定-deep-q-learning-的解决方案" tabindex="-1">稳定 Deep Q-Learning 的解决方案： <a class="header-anchor" href="#稳定-deep-q-learning-的解决方案" aria-label="Permalink to “稳定 Deep Q-Learning 的解决方案：”">​</a></h2><ul><li>经验回放： 创建回放记忆以保存可以在训练期间重复使用的经验样本。这允许智能体多次从相同的经验中学习。此外，它使智能体在获得新经验时避免忘记以前的经验。从回放缓冲区中随机抽样可以消除观察序列中的相关性，并防止动作值发生灾难性的振荡或发散。</li><li>Fixed Q-Target： 为了计算 Q-Target，我们需要使用 Bellman 方程估计下一状态的折扣最优 Q 值 。问题是使用相同的网络权重来计算 Q-Target 和 Q-value。这意味着每次我们修改 Q-value 时， Q-Target 也会随之移动。为避免此问题，使用具有固定参数的单独网络来估计时间差异目标。 在某些 C 步骤 之后，通过从我们的深度 Q 网络复制参数来更新目标网络。</li><li>Double DQN： 处理 Q-Values 高估 的方法。该解决方案使用两个网络将动作选择与目标值 生成 解耦：- DQN 网络 为下一个状态选择最佳动作（具有最高 Q 值 的动作）- 目标网络 计算目标 Q- 在下一个状态下采取该行动的 价值。 这种方法减少了 Q 值的 高估，有助于更快地训练和更稳定的学习。</li></ul>`,35)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};